// Bestellung per Token aus gemeinsamer Datei laden
const fs = require('fs');
const SHARED = '/tmp/yauno_data.json';
let shared = {};
try { shared = JSON.parse(fs.readFileSync(SHARED, 'utf8')); } catch(e) {}

const query = $input.first().json.query || {};
const token = query.token;

if (!token) {
  return [{ json: { error: 'Token parameter fehlt', code: 400 } }];
}

const tokens = shared.tokens || {};
const chatId = tokens[token];

if (!chatId) {
  return [{ json: { error: 'Ungültiger oder abgelaufener Token', code: 404 } }];
}

const bestellungen = shared.bestellungen || {};
const bestellung = bestellungen[chatId];

if (!bestellung) {
  return [{ json: { error: 'Bestellung nicht gefunden', code: 404 } }];
}

return [{ json: {
  chatId: bestellung.chatId,
  userName: bestellung.userName,
  positionen: bestellung.positionen,
  gesamtpreis: bestellung.gesamtpreis,
  token: token,
  zeitpunkt: bestellung.zeitpunkt,
  code: 200
}}];
